class ToastManager{constructor(){this.container=null;this.toasts=new Map();this.defaultDuration=4000;this.maxToasts=5;this.init();}init(){const container=document.createElement('div');container.id='toast-container';container.className='toast-container';document.body.appendChild(container);this.container=container;if(!document.getElementById('toast-styles')){this.addStyles();}}addStyles(){const style=document.createElement('style');style.id='toast-styles';style.textContent=` .toast-container{position: fixed;top: 24px;right: 24px;z-index: 9999;display: flex;flex-direction: column;gap: 12px;max-width: 420px;pointer-events: none;}.toast{display: flex;align-items: center;gap: 12px;padding: 14px 16px;background: var(--md-sys-color-surface,#fff);border-radius: 12px;box-shadow: 0 8px 32px rgba(0,0,0,0.16);pointer-events: auto;animation: toastSlideIn 0.3s ease-out;backdrop-filter: blur(10px);border-left: 4px solid;transform: translateX(0);opacity: 1;transition: transform 0.3s ease,opacity 0.3s ease;}.toast.hiding{animation: toastSlideOut 0.3s ease-in forwards;}.toast--success{border-color: #10b981;}.toast--error{border-color: #ef4444;}.toast--warning{border-color: #f59e0b;}.toast--info{border-color: #3b82f6;}.toast--loading{border-color: #6366f1;}.toast-icon{flex-shrink: 0;width: 24px;height: 24px;display: flex;align-items: center;justify-content: center;}.toast-icon .material-symbols-outlined{font-size: 20px;}.toast--success .toast-icon{color: #10b981;}.toast--error .toast-icon{color: #ef4444;}.toast--warning .toast-icon{color: #f59e0b;}.toast--info .toast-icon{color: #3b82f6;}.toast--loading .toast-icon{color: #6366f1;}.toast-content{flex: 1;min-width: 0;}.toast-title{font-weight: 600;font-size: 14px;color: var(--md-sys-color-on-surface,#1f2937);margin-bottom: 2px;}.toast-message{font-size: 13px;color: var(--md-sys-color-on-surface-variant,#6b7280);line-height: 1.4;}.toast-close{flex-shrink: 0;width: 28px;height: 28px;border: none;background: transparent;border-radius: 8px;cursor: pointer;display: flex;align-items: center;justify-content: center;color: var(--md-sys-color-on-surface-variant,#6b7280);transition: background 0.2s;}.toast-close:hover{background: rgba(0,0,0,0.05);}.toast-progress{position: absolute;bottom: 0;left: 0;height: 3px;background: currentColor;opacity: 0.3;animation: toastProgress linear forwards;}@keyframes toastSlideIn{from{transform: translateX(400px);opacity: 0;}to{transform: translateX(0);opacity: 1;}}@keyframes toastSlideOut{from{transform: translateX(0);opacity: 1;}to{transform: translateX(400px);opacity: 0;}}@keyframes toastProgress{from{width: 100%;}to{width: 0%;}}@media(prefers-color-scheme: dark){.toast{background: rgba(30,30,30,0.95);}.toast-title{color: #f3f4f6;}.toast-message{color: #9ca3af;}.toast-close:hover{background: rgba(255,255,255,0.1);}}@media(max-width: 640px){.toast-container{top: auto;bottom: 24px;left: 16px;right: 16px;max-width: none;}.toast{border-radius: 10px;}}`;document.head.appendChild(style);}show(message,type='info',options={}){const{title='',duration=this.defaultDuration,closable=true,icon=null,action=null}=options;const toastId=`toast-${Date.now()}-${Math.random().toString(36).substr(2,9)}`;if(this.toasts.size>=this.maxToasts){const oldestId=this.toasts.keys().next().value;this.hide(oldestId);}const toast=document.createElement('div');toast.id=toastId;toast.className=`toast toast--${type}`;const icons={success: 'check_circle',error: 'error',warning: 'warning',info: 'info',loading: 'progress_activity'};const iconChar=icon||icons[type];toast.innerHTML=`<div class="toast-icon"><span class="material-symbols-outlined">${iconChar}</span></div><div class="toast-content">${title ? `<div class="toast-title">${title}</div>` : ''}<div class="toast-message">${message}</div></div>${closable ? `<button class="toast-close" aria-label="Đóng"><span class="material-symbols-outlined">close</span></button>` : ''}${duration>0&&type!=='loading' ? `<div class="toast-progress" style="animation-duration: ${duration}ms;color: ${this.getProgressColor(type)}"></div>` : ''}`;if(action){const actionBtn=document.createElement('button');actionBtn.className='toast-action';actionBtn.textContent=action.label;actionBtn.onclick=()=>{action.onClick();this.hide(toastId);};toast.querySelector('.toast-content').appendChild(actionBtn);}if(closable){toast.querySelector('.toast-close').addEventListener('click',()=>{this.hide(toastId);});}this.container.appendChild(toast);this.toasts.set(toastId,{toast,type});if(duration>0&&type!=='loading'){setTimeout(()=>this.hide(toastId),duration);}return toastId;}getProgressColor(type){const colors={success: '#10b981',error: '#ef4444',warning: '#f59e0b',info: '#3b82f6',loading: '#6366f1'};return colors[type]||'#3b82f6';}hide(toastId){const toastData=this.toasts.get(toastId);if(!toastData)return;const{toast}=toastData;toast.classList.add('hiding');setTimeout(()=>{toast.remove();this.toasts.delete(toastId);},300);}hideAll(){this.toasts.forEach((_,id)=>this.hide(id));}success(message,options={}){return this.show(message,'success',options);}error(message,options={}){return this.show(message,'error',options);}warning(message,options={}){return this.show(message,'warning',options);}info(message,options={}){return this.show(message,'info',options);}loading(message,options={}){return this.show(message,'loading',{...options,closable: false,duration: 0});}}const Toast=new ToastManager();export default{Toast,ToastManager};